WEBHOOK="https://personal-os-five-black.vercel.app/api/webhooks?type=email"
SUCCESS=0
FAIL=0

push() {
  local LABEL="$1"
  local PAYLOAD="$2"
  RESP=$(curl -s -o /dev/null -w "%{http_code}" -X POST "$WEBHOOK" \
    -H "Content-Type: application/json" \
    -d "$PAYLOAD" \
    --max-time 15)
  if [[ "$RESP" == "200" || "$RESP" == "201" ]]; then
    echo "✓ $LABEL"
    SUCCESS=$((SUCCESS+1))
  else
    echo "✗ $LABEL  [HTTP $RESP]"
    FAIL=$((FAIL+1))
  fi
}

